INSERT INTO ai_usage_logs (book_id, operation_type, node_name, model, prompt_tokens, completion_tokens, total_tokens, estimated_cost_eur, metadata) 
VALUES (
  '{{ $node["Webhook Router"].json.body.bookId || $node["Init Book (Optional)"].json.id }}'::uuid,
  '{{ $node["Webhook Router"].json.body.action }}',
  'Agent: Writer',
  '{{ $node["Get Book"].json.primary_model || "gpt-4o" }}',
  {{ $json.usage ? $json.usage.prompt_tokens : 0 }},
  {{ $json.usage ? $json.usage.completion_tokens : 0 }},
  {{ $json.usage ? $json.usage.total_tokens : 0 }},
  {{ 
    (function() {
      const model = $node["Get Book"].json.primary_model || "gpt-4o";
      const isMini = model.includes("mini");
      const inPrice = isMini ? 0.00000015 : 0.0000025;
      const outPrice = isMini ? 0.00000060 : 0.00001;
      const promptTokens = $json.usage ? $json.usage.prompt_tokens : 0;
      const completionTokens = $json.usage ? $json.usage.completion_tokens : 0;
      return (promptTokens * inPrice + completionTokens * outPrice) * 1.05;
    })()
  }},
  '{{ JSON.stringify($json.usage || {}) }}'::jsonb
)

